var gr = new GlideRecord('incident');
gr.addQuery('major_incident_state', '!=', '');
gr.addQuery('sys_created_on', '>=', gs.hoursAgoStart(24));
gr.orderByDesc('sys_created_on');
gr.query();
while (gr.next()) {
  gs.print(gr.number + ' | ' + gr.getDisplayValue('business_service') + ' | ' + gr.getDisplayValue('state'));
}

var ProblemCandidateUtil = Class.create();
ProblemCandidateUtil.prototype = {
  hasThreshold: function(ciSysId, threshold) {
    var agg = new GlideAggregate('incident');
    agg.addQuery('cmdb_ci', ciSysId);
    agg.addQuery('opened_at', '>=', gs.daysAgoStart(7));
    agg.addAggregate('COUNT');
    agg.query();
    if (agg.next()) {
      return parseInt(agg.getAggregate('COUNT'), 10) >= parseInt(threshold, 10);
    }
    return false;
  },
  type: 'ProblemCandidateUtil'
};

var conflict = new GlideRecord('change_request');
conflict.addQuery('cmdb_ci', current.cmdb_ci);
conflict.addQuery('sys_id', '!=', current.sys_id);
conflict.addQuery('state', 'NOT IN', '3,4,7');
conflict.addQuery('start_date', '<', current.end_date);
conflict.addQuery('end_date', '>', current.start_date);
conflict.query();
if (conflict.next()) {
  gs.addErrorMessage('A conflicting change already exists for this CI in the selected window.');
  current.setAbortAction(true);
}

var app = new GlideRecord('cmdb_ci_business_app');
app.addNullQuery('owned_by');
app.addNotNullQuery('support_group');
app.query();
while (app.next()) {
  var grp = new GlideRecord('sys_user_group');
  if (grp.get(app.support_group) && grp.manager) {
    app.owned_by = grp.manager;
    app.update();
  }
}

var agg = new GlideAggregate('cmdb_ci');
agg.addNotNullQuery('name');
agg.groupBy('sys_class_name');
agg.groupBy('name');
agg.addAggregate('COUNT');
agg.query();
while (agg.next()) {
  var count = parseInt(agg.getAggregate('COUNT'), 10);
  if (count > 1) {
    gs.print(agg.getValue('sys_class_name') + ' | ' + agg.getValue('name') + ' | duplicates=' + count);
  }
}

var midName = 'mid.server.your_name';
var ecc = new GlideRecord('ecc_queue');
ecc.addQuery('agent', midName);
ecc.addQuery('sys_created_on', '>=', gs.daysAgoStart(2));
ecc.addQuery('state', 'error');
ecc.orderByDesc('sys_created_on');
ecc.query();
while (ecc.next()) {
  gs.print(ecc.sys_created_on + ' | ' + ecc.topic + ' | ' + ecc.name);
}

if (current.cmdb_ci) {
  var ci = new GlideRecord('cmdb_ci');
  if (ci.get(current.cmdb_ci) && ci.support_group) {
    current.assignment_group = ci.support_group;
  }
}

var agg = new GlideAggregate('sn_si_incident');
agg.addQuery('active', true);
agg.groupBy('state');
agg.addAggregate('COUNT');
agg.query();
while (agg.next()) {
  gs.print(agg.getDisplayValue('state') + ' | ' + agg.getAggregate('COUNT'));
}

var asset = new GlideRecord('alm_asset');
if (asset.get('PUT_ASSET_SYS_ID_HERE')) {
  asset.stockroom = 'PUT_STOCKROOM_SYS_ID_HERE';
  asset.location = 'PUT_LOCATION_SYS_ID_HERE';
  asset.work_notes = 'Asset transferred as part of approved stockroom move.';
  asset.update();
}

var inst = new GlideRecord('cmdb_sam_sw_install');
inst.addNullQuery('display_name');
inst.orderByDesc('sys_created_on');
inst.query();
while (inst.next()) {
  gs.print(inst.discovery_model + ' | ' + inst.publisher + ' | ' + inst.version);
}

var gr = new GlideRecord('sn_vul_vulnerable_item');
gr.addActiveQuery();
gr.addQuery('opened_at', '<=', gs.daysAgoStart(30));
gr.query();
while (gr.next()) {
  gs.print(gr.number + ' | ' + gr.getDisplayValue('assignment_group') + ' | ' + gr.getDisplayValue('cmdb_ci'));
}

var SecureIncidentReader = Class.create();
SecureIncidentReader.prototype = {
  getActiveIncidentNumbers: function() {
    var out = [];
    var gr = new GlideRecordSecure('incident');
    gr.addActiveQuery();
    gr.setLimit(20);
    gr.query();
    while (gr.next()) {
      out.push(gr.getValue('number'));
    }
    return out.join(',');
  },
  type: 'SecureIncidentReader'
};

var gr = new GlideRecord('cmdb_ci_server');
gr.addEncodedQuery('last_discoveredRELATIVELE@dayofweek@ago@90^install_status!=7');
gr.query();
while (gr.next()) {
  gs.print(gr.name + ' | ' + gr.getDisplayValue('last_discovered'));
}

var threshold = 80;
var gr = new GlideRecord('sn_vdr_risk_assessment');
gr.addQuery('score', '>=', threshold);
gr.query();
while (gr.next()) {
  gs.print(gr.getDisplayValue() + ' | ' + gr.getDisplayValue('owner') + ' | ' + gr.getDisplayValue('state'));
}

var prb = new GlideRecord('problem');
if (prb.get('PUT_PROBLEM_SYS_ID_HERE') && prb.workaround) {
  var kb = new GlideRecord('kb_knowledge');
  kb.initialize();
  kb.short_description = 'Known error workaround for ' + prb.number;
  kb.text = prb.workaround;
  kb.workflow_state = 'draft';
  kb.insert();
}
